import { moduleMetadata } from '@storybook/angular';
import { PfHighlightPipe } from './highlight.pipe';
import { PfInputComponent } from '../input/input.component';
const meta = {
    title: 'Composants/Highlight',
    tags: ['autodocs'],
    parameters: {
        docs: {
            description: {
                component: "Pipe `pfHighlight` : surligne les occurrences d'une `query` dans une chaîne en utilisant des `<mark>` natifs HTML5. Sécurité : le texte est échappé avant l'injection des marks.",
            },
        },
    },
    decorators: [moduleMetadata({ imports: [PfHighlightPipe, PfInputComponent] })],
};
export default meta;
export const WithQuery = {
    render: () => ({
        props: { query: 'maritime' },
        template: `
      <p [innerHTML]="'Direction des affaires maritimes - Service de la navigation maritime côtière' | pfHighlight: query"></p>
    `,
    }),
};
export const SearchResults = {
    render: () => ({
        props: {
            query: 'permis',
            results: [
                'Permis bateau côtier',
                'Demande de permis hauturier',
                "Renouvellement d'un permis fluvial",
                "Inscription d'un navire",
            ],
        },
        template: `
      <div style="display: flex; flex-direction: column; gap: 12px; max-width: 480px;">
        <pf-input label="Rechercher" [value]="query" (valueChange)="query = $event" placeholder="Saisir une recherche…"></pf-input>
        <ul style="margin: 0; padding-left: 20px;">
          @for (r of results; track r) {
            <li [innerHTML]="r | pfHighlight: query"></li>
          }
        </ul>
      </div>
    `,
    }),
};
